import java.util.*;

public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
    // Define the order of business lines
    List<String> businessOrder = Arrays.asList("electronics", "grocery", "pharmacy", "restaurant");

    // Filter valid coupons
    List<String> validCodes = new ArrayList<>();
    for (int i = 0; i < code.length; ++i) {
        // Check if code is not empty and only contains allowed characters
        boolean isValidCode = !code[i].isEmpty();
        for (char c : code[i].toCharArray()) {
            if (!Character.isLetterOrDigit(c) && c != '_') {
                isValidCode = false;
                break;
            }
        }

        // Check if business line is valid
        boolean isValidBusiness = businessOrder.contains(businessLine[i]);

        // Check if active
        boolean isActive = isActive[i];

        if (isValidCode && isValidBusiness && isActive) {
            validCodes.add(code[i]);
        }
    }

    // Sort the valid coupons
    // First by business line order, then by code lexicographically
    validCodes.sort((a, b) -> {
        int idxA = businessOrder.indexOf(businessLine[findIndex(a, validCodes, code, businessLine)]);
        int idxB = businessOrder.indexOf(businessLine[findIndex(b, validCodes, code, businessLine)]);

        if (idxA != idxB) {
            return Integer.compare(idxA, idxB);
        } else {
            return a.compareTo(b);
        }
    });

    // Convert to array
    String[] result = new String[validCodes.size()];
    for (int i = 0; i < result.length; i++) {
        result[i] = validCodes.get(i);
    }
    return result;
}

private static int findIndex(String code, List<String> validCodes, String[] codeArray, String[] businessLineArray) {
    for (int i = 0; i < codeArray.length; i++) {
        if (codeArray[i].equals(code)) {
            return i;
        }
    }
    return -1;
}
